SELECT rating, comments
FROM instructor_evaluations
WHERE rating = 5;

SELECT course_id, AVG(rating) AS average_rating
FROM course_evaluations
GROUP BY course_id;

SELECT rating, COUNT(evaluation_id) as evaluation_count
FROM instructor_evaluations
GROUP BY rating;

SELECT AVG(rating) AS average_instructor_rating
FROM instructor_evaluations
WHERE evaluation_date >= '2017-01-01' AND evaluation_date <= '2017-12-31';

SELECT DISTINCT course_name
FROM courses
WHERE course_id IN (
    SELECT course_id
    FROM course_evaluations
);

SELECT MAX(avg_attendance) AS highest_average_attendance
FROM (
    SELECT AVG(attendance) AS avg_attendance
    FROM course_enrollments
    GROUP BY course_id
) AS course_avg_attendance;
